// Validate and extract webhook payload
const body = items[0].json.body || items[0].json;

const jobTitle = body.jobTitle || '';
const location = body.location || '';
const country = body.country || 'United States';

if (!jobTitle) {
  throw new Error('jobTitle is required');
}

if (!location) {
  throw new Error('location is required');
}

return [{
  json: {
    jobTitle,
    location,
    country,
    searchId: `search-${Date.now()}`,
    timestamp: new Date().toISOString()
  }
}];

// Parse LinkedIn HTML response (basic extraction)
const html = items[0].json || items[0].binary?.data?.toString() || '';

if (!html || html.length < 100) {
  throw new Error('Invalid HTML response from ScraperAPI');
}

// Extract job cards (simplified regex, production would use cheerio)
const jobMatches = html.matchAll(/<div[^>]*class="[^"]*base-card[^"]*"[^>]*>[\s\S]*?<\/div>/gi);
const jobs = [];

for (const match of jobMatches) {
  const card = match[0];

  const titleMatch = card.match(/<h3[^>]*>([^<]+)<\/h3>/i);
  const companyMatch = card.match(/<h4[^>]*>([^<]+)<\/h4>/i);
  const locationMatch = card.match(/<span[^>]*class="[^"]*location[^"]*"[^>]*>([^<]+)<\/span>/i);
  const linkMatch = card.match(/href="([^"]+)"/i);

  if (titleMatch && companyMatch) {
    jobs.push({
      jobTitle: titleMatch[1].trim(),
      company: companyMatch[1].trim(),
      location: locationMatch ? locationMatch[1].trim() : 'Not specified',
      applyUrl: linkMatch ? linkMatch[1] : '',
      source: 'LinkedIn (ScraperAPI)',
      scrapedDate: new Date().toISOString().split('T')[0]
    });
  }

  if (jobs.length >= 20) break; // Limit to 20 jobs
}

if (jobs.length === 0) {
  throw new Error('No jobs extracted from HTML');
}

return jobs.map(job => ({ json: job }));

// Parse Remotive fallback
const response = items[0].json;
const jobs = response.jobs || [];

return jobs.slice(0, 20).map(job => ({
  json: {
    jobTitle: job.title || 'Unknown',
    company: job.company_name || 'Unknown',
    location: job.candidate_required_location || 'Remote',
    applyUrl: job.url || '',
    source: 'Remotive (Fallback)',
    scrapedDate: new Date().toISOString().split('T')[0]
  }
}));

// Parse Arbeitnow fallback
const response = items[0].json;
const jobs = response.data || [];

return jobs.slice(0, 20).map(job => ({
  json: {
    jobTitle: job.title || 'Unknown',
    company: job.company_name || 'Unknown',
    location: job.location || 'Remote',
    applyUrl: job.url || '',
    source: 'Arbeitnow (Fallback)',
    scrapedDate: new Date().toISOString().split('T')[0]
  }
}));

// Deduplicate and add metadata
const searchId = $('Validate Input').item.json.searchId;
const searchQuery = $('Validate Input').item.json.jobTitle;
const searchLocation = $('Validate Input').item.json.location;

const jobs = items.map(item => item.json);
const seen = new Set();
const unique = [];

for (const job of jobs) {
  const key = `${job.company}-${job.jobTitle}`.toLowerCase().replace(/\s+/g, '-');
  if (!seen.has(key) && job.applyUrl) {
    seen.add(key);
    unique.push({
      ...job,
      searchId,
      searchQuery,
      searchLocation,
      status: 'New'
    });
  }
}

return unique.map(job => ({ json: job }));

// Prepare webhook response
const jobs = items.map(item => item.json);
const total = jobs.length;

const sourceBreakdown = jobs.reduce((acc, j) => {
  acc[j.source] = (acc[j.source] || 0) + 1;
  return acc;
}, {});

return [{
  json: {
    success: true,
    totalJobs: total,
    searchId: jobs[0]?.searchId || 'unknown',
    searchQuery: jobs[0]?.searchQuery || '',
    searchLocation: jobs[0]?.searchLocation || '',
    sources: sourceBreakdown,
    message: `Successfully scraped ${total} jobs`,
    timestamp: new Date().toISOString()
  }
}];
